{
  "parameters": "z.object({ armorPiece: z.enum(['helmet', 'chestplate', 'leggings', 'boots', 'all']).default('all').describe("The specific leather armor piece to equip, or 'all' to attempt equipping a full set.") })",
  "executionArgs": {
    "armorPiece": "all"
  },
  "code": "const armorConfig = {
  helmet: { name: 'leather_helmet', slot: 'head' },
  chestplate: { name: 'leather_chestplate', slot: 'torso' },
  leggings: { name: 'leather_leggings', slot: 'legs' },
  boots: { name: 'leather_boots', slot: 'feet' }
};

const piecesToEquip = args.armorPiece === 'all' 
  ? ['helmet', 'chestplate', 'leggings', 'boots'] 
  : [args.armorPiece];

const results = [];
for (const piece of piecesToEquip) {
  const config = armorConfig[piece];
  const item = bot.inventory.items().find(function(i) { 
    return i.name === config.name || i.name === config.name.replace('chestplate', 'tunic');
  });

  if (item) {
    // Check if the slot is already occupied by this specific item to avoid redundant actions
    const equippedItem = bot.inventory.equipment[config.slot];
    if (equippedItem && equippedItem.name === item.name) {
      results.push("Already wearing " + piece);
      continue;
    }

    try {
      await bot.equip(item, config.slot);
      results.push("Equipped " + config.name);
    } catch (err) {
      results.push("Failed to equip " + config.name + ": " + err.message);
    }
  } else {
    results.push("Missing " + config.name);
  }
}

return "Armor Status: " + results.join(', ') + ".";"
}
